    type: DataTypes.INTEGER,
    allowNull: false
  },
  imageableType: {
    type: DataTypes.STRING,
    allowNull: false
  }
});

User.hasMany(Image, {
  as: "profilePictures",
  foreignKey: "imageableId",
  constraints: false,
  scope: {
    imageableType: "user"
  }
});

Product.hasMany(Image, {
  as: "productPhotos",
  foreignKey: "imageableId",
  constraints: false,
  scope: {
    imageableType: "product"
  }
});

Image.belongsTo(User, {
  as: "user",
  foreignKey: "imageableId",
  constraints: false
});

Image.belongsTo(Product, {
  as: "product",
  foreignKey: "imageableId",
  constraints: false
});

